 1→import { generateId } from './ids';
 2→import { WALL_THICKNESS, DOOR_WIDTH, WINDOW_WIDTH, ROOM_COLOR } from './defaults';
 3→import { polygonArea, polygonCentroid } from '@/geometry/polygon';
 4→
 5→export function createProject(name = 'Untitled Project') {
 6→  return {
 7→    id: generateId('proj'),
 8→    name,
 9→    createdAt: new Date().toISOString(),
10→    updatedAt: new Date().toISOString(),
11→    floors: [createFloor('Ground Floor', 0)],
12→    version: 1,
13→  };
14→}
15→
16→export function createFloor(name = 'Floor', level = 0) {
17→  return {
18→    id: generateId('floor'),
19→    name,
20→    level,
21→    walls: [],
22→    rooms: [],
23→    doors: [],
24→    windows: [],
25→  };
26→}
27→
28→export function createWall(start, end, thickness = WALL_THICKNESS) {
29→  return {
30→    id: generateId('wall'),
31→    start: { x: start.x, y: start.y },
32→    end: { x: end.x, y: end.y },
33→    thickness,
34→  };
35→}
36→
37→export function createDoor(wallId, offset, width = DOOR_WIDTH, openDirection = 'left', type = 'swing') {
38→  return {
39→    id: generateId('door'),
40→    wallId,
41→    offset,
42→    width,
43→    openDirection,
44→    type,
45→  };
46→}
47→
48→export function createWindow(wallId, offset, width = WINDOW_WIDTH, type = 'standard', openDirection = 'left') {
49→  return {
50→    id: generateId('win'),
51→    wallId,
52→    offset,
53→    width,
54→    type,
55→    openDirection,
56→  };
57→}
58→
59→export function createRoom(name = 'Room', points = [], color = ROOM_COLOR) {
60→  const area = polygonArea(points);
61→  const centroid = points.length >= 3 ? polygonCentroid(points) : { x: 0, y: 0 };
62→  return {
63→    id: generateId('room'),
64→    name,
65→    points: points.map(p => ({ x: p.x, y: p.y })),
66→    labelPosition: { ...centroid },
67→    color,
68→    area,
69→  };
70→}
