  1→import { useState, useEffect, useCallback } from 'react';
  2→import { ProjectProvider, useProject } from './ProjectProvider';
  3→import { EditorProvider } from './EditorProvider';
  4→import SvgCanvas from '@/renderers/SvgCanvas';
  5→import Toolbar from '@/ui/Toolbar';
  6→import Sidebar from '@/ui/Sidebar';
  7→import PropertiesPanel from '@/ui/PropertiesPanel';
  8→import Modal from '@/ui/Modal';
  9→import { createProject } from '@/domain/models';
 10→import { saveProject, loadProject, listProjects } from '@/persistence/storage';
 11→import { useAutosave } from '@/persistence/useAutosave';
 12→import styles from './App.module.css';
 13→
 14→function AppInner() {
 15→  const { project, isDirty, dispatch } = useProject();
 16→  const [showLoadModal, setShowLoadModal] = useState(false);
 17→  const [savedProjects, setSavedProjects] = useState([]);
 18→
 19→  useAutosave(project, isDirty, dispatch);
 20→
 21→  // beforeunload warning
 22→  useEffect(() => {
 23→    const handler = (e) => {
 24→      if (isDirty) {
 25→        e.preventDefault();
 26→        e.returnValue = '';
 27→      }
 28→    };
 29→    window.addEventListener('beforeunload', handler);
 30→    return () => window.removeEventListener('beforeunload', handler);
 31→  }, [isDirty]);
 32→
 33→  const handleNew = useCallback(() => {
 34→    if (isDirty && !window.confirm('Unsaved changes will be lost. Continue?')) return;
 35→    dispatch({ type: 'PROJECT_NEW', project: createProject() });
 36→  }, [isDirty, dispatch]);
 37→
 38→  const handleSave = useCallback(async () => {
 39→    await saveProject(project);
 40→    dispatch({ type: 'MARK_SAVED' });
 41→  }, [project, dispatch]);
 42→
 43→  // Ctrl+S save
 44→  useEffect(() => {
 45→    const handler = (e) => {
 46→      if ((e.ctrlKey || e.metaKey) && e.key === 's') {
 47→        e.preventDefault();
 48→        handleSave();
 49→      }
 50→    };
 51→    window.addEventListener('keydown', handler);
 52→    return () => window.removeEventListener('keydown', handler);
 53→  }, [handleSave]);
 54→
 55→  const handleLoadClick = useCallback(async () => {
 56→    setSavedProjects(await listProjects());
 57→    setShowLoadModal(true);
 58→  }, []);
 59→
 60→  const handleLoad = useCallback(async (id) => {
 61→    if (isDirty && !window.confirm('Unsaved changes will be lost. Continue?')) return;
 62→    try {
 63→      const { project: loaded, savedAt } = await loadProject(id);
 64→      dispatch({ type: 'PROJECT_LOAD', project: loaded, savedAt });
 65→      setShowLoadModal(false);
 66→    } catch (err) {
 67→      alert('Failed to load project: ' + err.message);
 68→    }
 69→  }, [isDirty, dispatch]);
 70→
 71→  const activeFloorId = project.floors[0]?.id;
 72→
 73→  return (
 74→    <EditorProvider activeFloorId={activeFloorId}>
 75→      <div className={styles.layout}>
 76→        <div className={styles.toolbar}>
 77→          <Toolbar onNew={handleNew} onSave={handleSave} onLoad={handleLoadClick} />
 78→        </div>
 79→        <div className={styles.sidebar}>
 80→          <Sidebar />
 81→        </div>
 82→        <div className={styles.canvas}>
 83→          <SvgCanvas />
 84→        </div>
 85→        <div className={styles.properties}>
 86→          <PropertiesPanel />
 87→        </div>
 88→      </div>
 89→
 90→      {showLoadModal && (
 91→        <Modal title="Load Project" onClose={() => setShowLoadModal(false)}>
 92→          {savedProjects.length === 0 ? (
 93→            <p style={{ color: 'var(--color-text-secondary)', fontSize: '13px' }}>
 94→              No saved projects found.
 95→            </p>
 96→          ) : (
 97→            <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
 98→              {savedProjects.map(p => (
 99→                <button
100→                  key={p.id}
101→                  onClick={() => handleLoad(p.id)}
102→                  style={{
103→                    display: 'flex',
104→                    justifyContent: 'space-between',
105→                    padding: '10px 12px',
106→                    border: '1px solid var(--color-border)',
107→                    borderRadius: 'var(--radius-sm)',
108→                    cursor: 'pointer',
109→                    background: 'white',
110→                    fontSize: '13px',
111→                  }}
112→                >
113→                  <span style={{ fontWeight: 500 }}>{p.name}</span>
114→                  <span style={{ color: 'var(--color-text-secondary)', fontSize: '11px' }}>
115→                    {new Date(p.savedAt).toLocaleDateString()}
116→                  </span>
117→                </button>
118→              ))}
119→            </div>
120→          )}
121→          <button
122→            onClick={() => setShowLoadModal(false)}
123→            style={{
124→              marginTop: '16px',
125→              padding: '8px 16px',
126→              border: '1px solid var(--color-border)',
127→              borderRadius: 'var(--radius-sm)',
128→              cursor: 'pointer',
129→              fontSize: '13px',
130→              background: 'white',
131→            }}
132→          >
133→            Cancel
134→          </button>
135→        </Modal>
136→      )}
137→    </EditorProvider>
138→  );
139→}
140→
141→export default function App() {
142→  return (
143→    <ProjectProvider>
144→      <AppInner />
145→    </ProjectProvider>
146→  );
147→}
