  1→import { signedPolygonArea } from './polygon';
  2→import { ENDPOINT_MERGE_TOLERANCE, MIN_ROOM_AREA } from '@/domain/defaults';
  3→
  4→/**
  5→ * Detect rooms from wall topology using planar graph face extraction.
  6→ * Returns array of { points: [{x,y}], area: number }.
  7→ */
  8→export function detectRooms(walls, mergeTolerance = ENDPOINT_MERGE_TOLERANCE) {
  9→  if (walls.length < 3) return [];
 10→
 11→  // Step A: Collect and merge endpoints
 12→  const rawPoints = [];
 13→  for (const wall of walls) {
 14→    rawPoints.push(wall.start, wall.end);
 15→  }
 16→
 17→  // Merge nearby points — O(n²), fine for apartment scale
 18→  const vertices = []; // [{x, y}]
 19→  const pointToVertex = new Map(); // index in rawPoints -> index in vertices
 20→
 21→  function findOrAddVertex(p) {
 22→    for (let i = 0; i < vertices.length; i++) {
 23→      const v = vertices[i];
 24→      const dx = v.x - p.x;
 25→      const dy = v.y - p.y;
 26→      if (dx * dx + dy * dy <= mergeTolerance * mergeTolerance) {
 27→        return i;
 28→      }
 29→    }
 30→    vertices.push({ x: p.x, y: p.y });
 31→    return vertices.length - 1;
 32→  }
 33→
 34→  // Build edges from walls
 35→  const edges = []; // [{from, to}] as vertex indices
 36→  for (const wall of walls) {
 37→    const fromIdx = findOrAddVertex(wall.start);
 38→    const toIdx = findOrAddVertex(wall.end);
 39→    if (fromIdx === toIdx) continue; // degenerate
 40→    edges.push({ from: fromIdx, to: toIdx });
 41→  }
 42→
 43→  // Build adjacency list with directed half-edges
 44→  const adj = new Array(vertices.length).fill(null).map(() => []);
 45→  const halfEdgeSet = new Set();
 46→
 47→  for (const { from, to } of edges) {
 48→    const keyA = `${from}-${to}`;
 49→    const keyB = `${to}-${from}`;
 50→    if (!halfEdgeSet.has(keyA)) {
 51→      halfEdgeSet.add(keyA);
 52→      adj[from].push(to);
 53→    }
 54→    if (!halfEdgeSet.has(keyB)) {
 55→      halfEdgeSet.add(keyB);
 56→      adj[to].push(from);
 57→    }
 58→  }
 59→
 60→  // Step B: Sort adjacency by angle
 61→  for (let i = 0; i < vertices.length; i++) {
 62→    const v = vertices[i];
 63→    adj[i].sort((a, b) => {
 64→      const angA = Math.atan2(vertices[a].y - v.y, vertices[a].x - v.x);
 65→      const angB = Math.atan2(vertices[b].y - v.y, vertices[b].x - v.x);
 66→      return angA - angB;
 67→    });
 68→  }
 69→
 70→  // Step C: Build next-half-edge map
 71→  // For half-edge (u->v), at vertex v find u in v's adj, then next is v -> adj[v][(idx-1+deg) % deg]
 72→  const nextHE = new Map(); // "u-v" -> "v-w"
 73→  for (const key of halfEdgeSet) {
 74→    const [uStr, vStr] = key.split('-');
 75→    const u = parseInt(uStr);
 76→    const v = parseInt(vStr);
 77→    const neighbors = adj[v];
 78→    const idx = neighbors.indexOf(u);
 79→    if (idx === -1) continue;
 80→    const nextIdx = (idx - 1 + neighbors.length) % neighbors.length;
 81→    const w = neighbors[nextIdx];
 82→    nextHE.set(key, `${v}-${w}`);
 83→  }
 84→
 85→  // Step D: Trace cycles
 86→  const visited = new Set();
 87→  const cycles = [];
 88→
 89→  for (const startKey of halfEdgeSet) {
 90→    if (visited.has(startKey)) continue;
 91→
 92→    const cycle = [];
 93→    let current = startKey;
 94→    let safe = 0;
 95→    const maxIter = vertices.length + 1;
 96→
 97→    while (!visited.has(current) && safe < maxIter) {
 98→      visited.add(current);
 99→      const [uStr] = current.split('-');
100→      cycle.push(parseInt(uStr));
101→      const next = nextHE.get(current);
102→      if (!next) break;
103→      current = next;
104→      safe++;
105→    }
106→
107→    // Check if we completed a cycle back to start
108→    if (current === startKey && cycle.length >= 3) {
109→      cycles.push(cycle);
110→    }
111→  }
112→
113→  // Step E: Filter and return
114→  const rooms = [];
115→  for (const cycle of cycles) {
116→    const points = cycle.map(i => vertices[i]);
117→    const signed = signedPolygonArea(points);
118→    // In screen coords (Y-down), CW winding = positive signed area = interior face
119→    if (signed <= 0) continue;
120→    const area = Math.abs(signed);
121→    if (area < MIN_ROOM_AREA) continue;
122→    rooms.push({ points, area });
123→  }
124→
125→  return rooms;
126→}
