1→export function serializeProject(project) {
2→  return {
3→    version: 1,
4→    data: project,
5→    savedAt: new Date().toISOString(),
6→  };
7→}
8→

 1→export function deserializeProject(json) {
 2→  if (!json || !json.version || !json.data) {
 3→    throw new Error('Invalid project data');
 4→  }
 5→  if (json.version !== 1) {
 6→    throw new Error(`Unsupported project version: ${json.version}`);
 7→  }
 8→
 9→  const project = json.data;
10→
11→  // Basic validation
12→  if (!project.id || !project.name || !Array.isArray(project.floors)) {
13→    throw new Error('Invalid project structure');
14→  }
15→
16→  for (const floor of project.floors) {
17→    if (!floor.id || !Array.isArray(floor.walls)) {
18→      throw new Error('Invalid floor structure');
19→    }
20→  }
21→
22→  // Backfill missing room fields for old saves
23→  for (const floor of project.floors) {
24→    if (!floor.rooms) floor.rooms = [];
25→    for (const room of floor.rooms) {
26→      if (!room.points) room.points = [];
27→      if (room.area === undefined) room.area = 0;
28→    }
29→  }
30→
31→  // Backfill door/window type fields for old saves
32→  for (const floor of project.floors) {
33→    if (!floor.doors) floor.doors = [];
34→    for (const door of floor.doors) {
35→      if (!door.type) door.type = 'swing';
36→    }
37→    if (!floor.windows) floor.windows = [];
38→    for (const win of floor.windows) {
39→      if (!win.type) win.type = 'standard';
40→      if (!win.openDirection) win.openDirection = 'left';
41→    }
42→  }
43→
44→  return { project, savedAt: json.savedAt };
45→}
46→

 1→import { serializeProject } from './serialize';
