194→export default function PropertiesPanel() {
195→  const { project, dispatch } = useProject();
196→  const { selectedId, selectedType, activeFloorId, dispatch: editorDispatch } = useEditor();
197→  const floor = project.floors.find(f => f.id === activeFloorId);
198→
199→  const handleDelete = () => {
200→    if (!selectedId) return;
201→    if (selectedType === 'wall') {
202→      dispatch({ type: 'WALL_DELETE', floorId: activeFloorId, wallId: selectedId });
203→    } else if (selectedType === 'door') {
204→      dispatch({ type: 'DOOR_DELETE', floorId: activeFloorId, doorId: selectedId });
205→    } else if (selectedType === 'window') {
206→      dispatch({ type: 'WINDOW_DELETE', floorId: activeFloorId, windowId: selectedId });
207→    } else if (selectedType === 'room') {
208→      dispatch({ type: 'ROOM_DELETE', floorId: activeFloorId, roomId: selectedId });
209→    }
210→    editorDispatch({ type: 'DESELECT' });
211→  };
212→
213→  let content = <ProjectSummary project={project} floor={floor} />;
214→
215→  if (selectedId && floor) {
216→    if (selectedType === 'wall') {
217→      const wall = floor.walls.find(w => w.id === selectedId);
218→      if (wall) {
219→        content = <WallProperties wall={wall} dispatch={dispatch} floorId={activeFloorId} />;
220→      }
221→    } else if (selectedType === 'door') {
222→      const door = floor.doors.find(d => d.id === selectedId);
223→      const wall = door ? floor.walls.find(w => w.id === door.wallId) : null;
224→      if (door) {
225→        content = <DoorProperties door={door} wall={wall} dispatch={dispatch} floorId={activeFloorId} editorDispatch={editorDispatch} />;
226→      }
227→    } else if (selectedType === 'window') {
228→      const win = floor.windows.find(w => w.id === selectedId);
229→      const wall = win ? floor.walls.find(w => w.id === win.wallId) : null;
230→      if (win) {
231→        content = <WindowProperties window={win} wall={wall} dispatch={dispatch} floorId={activeFloorId} />;
232→      }
233→    } else if (selectedType === 'room') {
234→      const room = floor.rooms.find(r => r.id === selectedId);
235→      if (room) {
236→        content = <RoomProperties room={room} dispatch={dispatch} floorId={activeFloorId} />;
237→      }
238→    }
239→  }
240→
241→  return (
242→    <div className={styles.panel}>
243→      {content}
244→      {selectedId && (
245→        <button className={styles.deleteBtn} onClick={handleDelete}>
246→          Delete {selectedType}
247→        </button>
248→      )}
249→    </div>
250→  );
251→}
