 3→export default function InputField({ label, value, onChange, type = 'text', suffix, readOnly, step }) {
 4→  const handleChange = useCallback((e) => {
 5→    const val = type === 'number' ? parseFloat(e.target.value) : e.target.value;
 6→    if (type === 'number' && isNaN(val)) return;
 7→    onChange(val);
 8→  }, [onChange, type]);
 9→
10→  return (
11→    <div style={{
12→      display: 'flex',
13→      alignItems: 'center',
14→      gap: '8px',
15→      marginBottom: '8px',
16→    }}>
17→      <label style={{
18→        flex: '0 0 80px',
19→        fontSize: '12px',
20→        color: 'var(--color-text-secondary)',
21→      }}>
22→        {label}
23→      </label>
24→      <div style={{ display: 'flex', alignItems: 'center', flex: 1, gap: '4px' }}>
25→        <input
26→          type={type}
27→          value={value}
28→          onChange={handleChange}
29→          readOnly={readOnly}
30→          step={step}
31→          style={{
32→            flex: 1,
33→            height: '28px',
34→            padding: '0 8px',
35→            border: '1px solid var(--color-border)',
36→            borderRadius: 'var(--radius-sm)',
37→            fontSize: '12px',
38→            background: readOnly ? 'var(--color-panel-bg)' : 'white',
