 1→import { useEffect, useRef } from 'react';
 2→
 3→export default function Modal({ title, onClose, children }) {
 4→  const overlayRef = useRef(null);
 5→
 6→  useEffect(() => {
 7→    const handleKey = (e) => {
 8→      if (e.key === 'Escape') onClose();
 9→    };
10→    window.addEventListener('keydown', handleKey);
11→    return () => window.removeEventListener('keydown', handleKey);
12→  }, [onClose]);
13→
14→  const handleOverlayClick = (e) => {
15→    if (e.target === overlayRef.current) onClose();
16→  };
17→
18→  return (
19→    <div
20→      ref={overlayRef}
21→      onClick={handleOverlayClick}
22→      style={{
23→        position: 'fixed',
24→        inset: 0,
25→        background: 'rgba(0,0,0,0.4)',
26→        display: 'flex',
27→        alignItems: 'center',
28→        justifyContent: 'center',
29→        zIndex: 1000,
30→      }}
31→    >
32→      <div style={{
33→        background: 'white',
34→        borderRadius: 'var(--radius-md)',
35→        padding: 'var(--space-xl)',
36→        minWidth: '360px',
37→        maxWidth: '480px',
38→        boxShadow: '0 8px 32px rgba(0,0,0,0.15)',
39→      }}>
40→        <h3 style={{
41→          margin: '0 0 16px',
42→          fontSize: '16px',
43→          fontWeight: 600,
44→        }}>
45→          {title}
46→        </h3>
47→        {children}
48→      </div>
49→    </div>
50→  );
51→}
